import { randomUUID } from 'crypto';
import { db, queries } from '../../db';
import type { DockerStack, DockerStackDeployment } from '../../db';
import type { DockerStackServiceContext } from './context';
import {
  createDeploymentRecord,
  getComposeContentForDeployment,
  updateDeploymentError,
  updateDeploymentFinished,
  updateDeploymentStatus,
} from './deploymentDb';
import type { StackDeploymentResult } from './types';
import { getContainerInfo } from './containers';
import { resolveStackWorkingDir } from './pathUtils';

/**
 * Rollback a stack to a previous successful deployment
 */
export async function rollbackStack(
  ctx: DockerStackServiceContext,
  serverId: string,
  stackId: string,
  targetDeploymentId: string
): Promise<StackDeploymentResult> {
  const stack = queries.getDockerStack(stackId) as DockerStack | null;

  if (!stack) {
    return { success: false, error: 'Stack not found' };
  }

  if (stack.server_id !== serverId) {
    return { success: false, error: 'Stack does not belong to this server' };
  }

  if (stack.status === 'deploying') {
    return { success: false, error: 'Stack is already being deployed. Please wait for the current deployment to complete.' };
  }

  const targetDeployment = db.prepare(`
      SELECT * FROM docker_stack_deployments
      WHERE id = ? AND stack_id = ? AND status = 'success'
    `).get(targetDeploymentId, stackId) as (DockerStackDeployment & { git_commit_hash?: string }) | null;

  if (!targetDeployment) {
    return { success: false, error: 'Target deployment not found or was not successful' };
  }

  const stackWithGit = stack as typeof stack & { git_clone_path?: string };

  const rollbackComposeContent = getComposeContentForDeployment(targetDeploymentId);

  if (!rollbackComposeContent) {
    return { success: false, error: 'Could not retrieve compose content for rollback' };
  }

  const deploymentId = `deploy-${randomUUID()}`;
  const { workingDir } = resolveStackWorkingDir(stack);
  const now = Date.now();

  createDeploymentRecord(deploymentId, stackId, 'rollback', now, undefined, stack.build_location);
  updateDeploymentStatus(deploymentId, 'pending');

  db.prepare(`
      UPDATE docker_stack_deployments SET previous_compose_content = ? WHERE id = ?
    `).run(stack.compose_content, deploymentId);

  ctx.initDeploymentLogs(deploymentId);

  const log = (message: string, type: 'info' | 'error' | 'success' | 'warning' = 'info') => {
    ctx.emitLog(message, type, stackId, deploymentId);
  };

  log(`Rolling back to deployment ${targetDeploymentId.substring(0, 12)}...`);

  try {
    queries.updateDockerStack(stackId, { status: 'deploying' });
    updateDeploymentStatus(deploymentId, 'pulling');
    log('Preparing rollback workspace and deployment files...');

    db.prepare(`
        UPDATE docker_stacks
        SET compose_content = ?,
            has_pending_failure = 0,
            failed_compose_content = NULL,
            updated_at = ?
        WHERE id = ?
      `).run(rollbackComposeContent, now, stackId);

    let needsRebuild = false;
    if (targetDeployment.git_commit_hash && stackWithGit.git_clone_path && stack.source_type === 'github') {
      log(`Checking out commit ${targetDeployment.git_commit_hash.substring(0, 8)}...`);

      const checkoutResult = await ctx.sshService.executeCommand(
        serverId,
        `cd "${stackWithGit.git_clone_path}" && git fetch --all && git checkout ${targetDeployment.git_commit_hash}`
      );

      if (checkoutResult.exitCode === 0) {
        log(`Restored source files to commit ${targetDeployment.git_commit_hash.substring(0, 8)}`, 'success');

        const targetTitle = (targetDeployment as { git_commit_title?: string }).git_commit_title;
        db.prepare(`
            UPDATE docker_stack_deployments SET git_commit_hash = ?, git_commit_title = ? WHERE id = ?
          `).run(targetDeployment.git_commit_hash, targetTitle || null, deploymentId);

        db.prepare(`
            UPDATE docker_stacks SET git_last_commit = ? WHERE id = ?
          `).run(targetDeployment.git_commit_hash, stackId);

        const hasBuildContext = await ctx.sshService.executeCommand(
          serverId,
          `grep -E "^\\s*build:" "${workingDir}/docker-compose.yml"`
        );
        needsRebuild = hasBuildContext.exitCode === 0;
      } else {
        log(`Warning: Could not checkout commit ${targetDeployment.git_commit_hash.substring(0, 8)}: ${checkoutResult.stderr || checkoutResult.stdout}`, 'warning');
        log('Proceeding with compose-only rollback...', 'warning');
      }
    }

    log('Stopping current containers...');
    await ctx.sshService.executeCommand(
      serverId,
      `cd "${workingDir}" && docker compose down 2>&1 || true`
    );

    log('Applying rollback compose file...');
    await ctx.sshService.executeCommand(
      serverId,
      `cat > "${workingDir}/docker-compose.yml" << 'COMPOSE_EOF'\n${rollbackComposeContent}\nCOMPOSE_EOF`
    );

    if (needsRebuild) {
      log('Rebuilding containers with restored source files...');
      updateDeploymentStatus(deploymentId, 'building');

      const buildResult = await ctx.sshService.executeCommand(
        serverId,
        `cd "${workingDir}" && docker compose build --no-cache 2>&1`
      );

      if (buildResult.exitCode !== 0) {
        throw new Error(`Failed to rebuild containers: ${buildResult.stderr || buildResult.stdout}`);
      }

      log('Rebuild completed successfully', 'success');
    }

    updateDeploymentStatus(deploymentId, 'starting');
    log('Starting containers with rollback configuration...');

    const upResult = await ctx.sshService.executeCommand(
      serverId,
      `cd "${workingDir}" && docker compose up -d 2>&1`
    );

    if (upResult.exitCode !== 0) {
      throw new Error(`Failed to start containers: ${upResult.stderr || upResult.stdout}`);
    }

    updateDeploymentStatus(deploymentId, 'success');
    updateDeploymentFinished(deploymentId, Date.now());

    queries.updateDockerStack(stackId, {
      status: 'running',
      last_deployed_at: Date.now(),
    });

    db.prepare(`
        UPDATE docker_stacks SET last_successful_deployment_id = ? WHERE id = ?
      `).run(deploymentId, stackId);

    const containers = await getContainerInfo(ctx, serverId, stack.project_name);

    log('Rollback completed successfully!', 'success');

    return {
      success: true,
      stackId,
      deploymentId,
      projectName: stack.project_name,
      containers,
    };
  } catch (error) {
    const errorMessage = error instanceof Error ? error.message : String(error);
    log(`Rollback failed: ${errorMessage}`, 'error');

    updateDeploymentStatus(deploymentId, 'failed');
    updateDeploymentError(deploymentId, errorMessage);
    updateDeploymentFinished(deploymentId, Date.now());

    queries.updateDockerStack(stackId, {
      status: 'error',
      last_error: errorMessage,
    });

    return {
      success: false,
      error: errorMessage,
    };
  } finally {
    ctx.saveDeploymentLogs(deploymentId);
  }
}
